import React from "react";
import { Box, Flex, Heading } from "rebass";

function Header() {
  return (
    <Flex>
      <Box width={1} alignItems="center" py={3} textAlign="center">
        <Heading fontSize={[5, 6, 7]} fontFamily="sans-serif">
          Douglas Cheong
        </Heading>
      </Box>
    </Flex>
  );
}

export default Header;
